/* ── Terminal ── */
.terminal {
  background: #0d1117;
  border: 1px solid #30363d;
  border-radius: 12px;
  padding: 24px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 16px;
  line-height: 1.8;
  margin: 16px 0;
}

.terminal .prompt { color: var(--accent-green); }
.terminal .cmd { color: var(--text-primary); }
.terminal .output { color: var(--text-secondary); }
.terminal .highlight-val { color: var(--accent-amber); }

/* ── Pill tags ── */
.tag {
  display: inline-block;
  padding: 6px 16px;
  border-radius: 20px;
  font-size: 14px;
  font-weight: 600;
  margin-right: 8px;
  margin-bottom: 8px;
}

/* ── GPU diagram ── */
.gpu-diagram {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 32px;
  margin: 24px 0;
}

.gpu-box {
  background: var(--bg-card);
  border: 2px solid var(--border);
  border-radius: 16px;
  padding: 24px 32px;
  text-align: center;
  min-width: 200px;
}

.gpu-box h4 {
  font-size: 16px;
  font-weight: 700;
  margin-bottom: 8px;
}

.gpu-box .gpu-usage {
  font-size: 36px;
  font-weight: 800;
}

.arrow-right {
  font-size: 32px;
  color: var(--accent-green);
}

/* ── Divider ── */
.divider {
  height: 1px;
  background: var(--border);
  margin: 28px 0;
}

.flex-grow { flex: 1; }

/* ── Cover specific ── */
.cover-center {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.cover-emoji {
  font-size: 72px;
  margin-bottom: 32px;
}

.cover-tags {
  margin-top: 40px;
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
}

.cover-tags .tag {
  background: rgba(59, 130, 246, 0.15);
  color: var(--accent-blue);
  font-size: 16px;
  padding: 10px 20px;
}
